export const VARIETY_CATEGORIES = ['All', 'Vegetables', 'Field Crops', 'Fodder Crops', 'Fruits & Ornamentals', 'Herbs & Spices'] as const;
export type VarietyCategory = typeof VARIETY_CATEGORIES[number];

export const getCropsForCategory = (category: string): string[] => {
  if (category === 'All') {
    return Array.from(new Set(VARIETY_DATA.map(v => v.cropEn))).sort();
  }
  return Array.from(new Set(VARIETY_DATA.filter(v => v.category === category).map(v => v.cropEn))).sort();
};